func newRunTestMCPServer(t *testing.T) *httptest.Server {
	t.Helper()

	s := mcp.NewServer(&mcp.Implementation{Name: "mcp-smoke", Version: "1.0.0"}, nil)
	s.AddTool(&mcp.Tool{
